-- ── Anomali ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Anomali is an enterprise threat intelligence and agentic SOC platform, built around its ThreatStream product, that helps security teams aggregate, enrich, and act on threat intelligence.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$approx 300 employees$q$, company_size),
  headquarters = COALESCE($q$Redwood City, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Anomali Review 2026: Threat Intelligence Platform Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Anomali is an enterprise threat intelligence platform built on ThreatStream. Learn about its history, features, pricing model, and target SOC customers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Anomali is an American cybersecurity company that provides an enterprise threat intelligence platform used by security operations center (SOC) teams to aggregate, correlate, and act on cyber threat intelligence. The company was founded in 2013 in Redwood City, California, originally under the name ThreatStream, by Greg Martin and Colby DeRodeff. It launched its first threat intelligence platform (TIP) product, also called ThreatStream, that year, designed to ingest threat data from many sources and help analysts track known threats and detect breaches faster. In 2016, the company rebranded from ThreatStream to Anomali while keeping the ThreatStream name for its flagship product. Anomali has raised substantial venture funding over multiple rounds, including a Series B led by General Catalyst Partners and a Series C led by Institutional Venture Partners (IVP), with total funding reported around $96 million by 2018 from investors including Paladin Capital Group, IVP, and GV (formerly Google Ventures). As of 2026, Anomali has approximately 300 employees and continues to operate as a private company headquartered in Redwood City. The core product, ThreatStream (now marketed as ThreatStream Next-Gen), aggregates threat intelligence feeds from open source, commercial, and government sources, applies AI-driven correlation and confidence scoring to reduce noise, and enriches security telemetry, logs, and alerts with context about threat actors, infrastructure, tactics, techniques, and procedures (TTPs), and campaigns in real time. Recent product updates emphasize agentic AI capabilities, including autonomous triage, scoring, and investigation steps intended to accelerate SOC workflows, with Anomali claiming performance improvements of up to 300 times faster investigation compared to traditional manual workflows in enterprise deployments. The platform is designed to integrate with or augment existing security infrastructure such as SIEMs, and can work alongside data lake platforms like Databricks or Snowflake. Anomali targets mid-market to large enterprise SOC teams, threat intelligence analysts, and incident responders rather than individual consumers or small businesses, and pricing is not publicly listed, instead requiring direct engagement with the company's sales team for a custom quote based on data volume, integrations, and deployment scope. It competes with other threat intelligence and SOC platforms such as Recorded Future, ThreatConnect, and Mandiant Advantage. Note: Anomali is unrelated to Anki, the flashcard app, despite the similar name prefix.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2a29cb73-32d8-421c-825e-8bf03a71343e';

