-- ── anon.li Alias ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$anon.li Alias is a privacy-focused email aliasing service that lets users generate disposable or custom email addresses to protect their real inbox from spam and data leaks.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$$2.49/month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Liechtenstein$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$anon.li Alias Review 2026: Email Aliasing Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$anon.li Alias is an open-source email aliasing tool for creating disposable and custom addresses. See features, pricing, and how it protects your inbox.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$anon.li Alias is the email aliasing product of anon.li, a privacy-focused, fully open-source platform based in Liechtenstein that also offers end-to-end encrypted file sharing (called Drop) and forms. Alias lets users generate a unique email identity for every website or service they sign up for, rather than exposing their real email address. Aliases can be random strings or custom, human-readable names (for example, shop@anon.li), and messages sent to an alias are forwarded to the user's real inbox; users can also reply through the alias without revealing their actual address. The product supports management through the anon.li website, a command-line interface (CLI), an API, a browser extension (available for Chrome and Firefox), and even an MCP (Model Context Protocol) integration aimed at AI agents that need to generate throwaway identities programmatically. Optional PGP encryption is available for forwarded mail on paid tiers. anon.li operates on a freemium model: the free tier includes a limited number of aliases (reported as around 10 random aliases plus 1 custom alias), while the paid Alias plan, priced at roughly $2.49 per month, unlocks unlimited random aliases, a larger allotment of custom aliases (around 100), and support for custom domains. anon.li also bundles Alias with its Drop file-sharing product at a combined price point for users who want both services. The entire codebase is open source under the GNU Affero General Public License v3.0 (AGPLv3) and published on both GitHub and Codeberg, reflecting a 'privacy by default, not by request' philosophy and zero-knowledge architecture where the platform itself cannot read forwarded content or shared files. Because the project is small, independent, and privacy-first, detailed public information about its founding date, team size, or funding is not available; it presents itself as a lean, community-oriented alternative to larger email alias and privacy services like SimpleLogin, AnonAddy (addy.io), or Firefox Relay, differentiating primarily through its open-source transparency, CLI/API/MCP access, and jurisdiction in privacy-friendly Liechtenstein. It is best suited for privacy-conscious individuals, developers, and increasingly AI agent workflows that need to generate disposable identities without manual sign-up steps.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '15e06305-a584-4637-8757-1e4f10f35e2b';

