-- ── anvil.works ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Anvil is a Python-based platform for building full-stack web applications, including the frontend, using only Python and no HTML, CSS, or JavaScript.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$$12/month$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$small team based in Cambridge, UK$q$, company_size),
  headquarters = COALESCE($q$Cambridge, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Anvil.works Review 2026: Python Web App Builder Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Anvil.works lets you build full-stack web apps with only Python. Compare pricing plans, features, and use cases for this no-code Python platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Anvil, at anvil.works, is a web application development platform that lets developers build complete full-stack web apps entirely in Python, without writing HTML, CSS, or JavaScript for the frontend. It was created by Meredydd Luff and Ian Davies, who met while completing PhDs at the University of Cambridge Computer Laboratory; Luff serves as CEO and Davies as COO, and the company operates from Cambridge, UK. The first working prototype of Anvil's development environment launched in 2017. Anvil's core differentiator is a drag-and-drop visual designer for building the user interface, paired with a Python code editor for both client-side (in-browser, compiled to run via Skulpt/similar Python-in-browser tooling) and server-side logic, plus a built-in relational database (Data Tables) and one-click cloud hosting, all managed from a single browser-based IDE. This lets Python developers, including those without web development (HTML/CSS/JavaScript) experience, build and deploy interactive web apps, internal tools, and dashboards much faster than assembling a traditional stack of separate frontend and backend frameworks. Anvil supports installing external Python libraries (including many PyPI packages) for use in both client and server code, integrates with Git for version control and CI/CD-style workflows, and offers features like scheduled background tasks, custom domains, and single sign-on (SSO) on higher tiers. Pricing follows a freemium SaaS model: a Free plan offers unlimited apps with shared cloud hosting, limited database rows (around 50,000) and storage (100 MB); a Hobby plan at roughly $12 per month (billed annually, or $14 month-to-month) adds scheduled tasks, a custom domain, and higher limits; a Business plan at roughly $89 per month (annual) or $99 (monthly) adds team collaboration, SSO, staging environments, and much higher data limits; and an Enterprise tier offers custom pricing with on-premise or dedicated-server deployment, isolated databases, and corporate authentication integration. Anvil also offers free educational licenses for students and educators. Its target audience includes Python developers building internal business tools, startups building MVPs quickly, data teams building dashboards on top of Python data science libraries, and educators teaching programming, and it competes with other low-code/no-code and rapid app-building platforms such as Streamlit, Retool, and Django-based scaffolding tools, differentiating primarily through its all-in-one, pure-Python, drag-and-drop approach to full-stack development.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c5d7d496-060b-494f-b8f1-4a7cae08eda5';

