-- ── Apache Netbeans ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Apache NetBeans is a free, open-source integrated development environment (IDE) for Java and other languages, now governed as a top-level Apache Software Foundation project.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1996, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Apache NetBeans Review 2026: Free Java IDE Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Apache NetBeans is a free, open-source IDE for Java, PHP, C/C++, and more. Learn its history from Sun to Oracle to Apache, features, and current status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Apache NetBeans is a free, open-source integrated development environment (IDE) primarily used for Java development, though it also supports PHP, C, C++, HTML5, JavaScript, Groovy, and other languages through extensions. Its origins trace back to 1996, when it began as Xelfi (a wordplay on Delphi), a student Java IDE project at the Faculty of Mathematics and Physics at Charles University in Prague. In 1997, Roman Staněk formed a company around the project and produced commercial versions until it was acquired by Sun Microsystems in 1999. Sun open-sourced NetBeans the following year, and the name itself, coined by architect Jaroslav Tulach, derives from Network and Java Beans. When Oracle acquired Sun Microsystems in 2010, NetBeans became an Oracle-owned product; under Oracle, the codebase was eventually unified with Oracle's own JDeveloper IDE around a shared NetBeans Platform architecture by 2012. In 2016, Oracle donated the NetBeans source code to the Apache Software Foundation, where it entered the Apache Incubator as a podling; the project graduated to become a full Top-Level Project of the Apache Software Foundation in April 2019, giving it the current name Apache NetBeans and community-driven, vendor-neutral governance. As of 2026, Apache NetBeans continues to be actively developed under this governance model, with Apache NetBeans 30 released in May 2026, reflecting a steady release cadence. The IDE provides a full suite of development tools including a code editor with syntax highlighting and code completion, visual GUI builders, debugging tools, profiling tools, version control integration (Git, Subversion, Mercurial), and project management features, all delivered as a completely free download with no licensing fees, tiers, or paid upgrades, consistent with its status as a fully open-source Apache Software Foundation project. Because it is community-governed rather than commercially operated, there is no company size, headquarters, or founding company in the traditional sense; contributions come from a distributed, volunteer-driven open-source community following Apache Software Foundation governance norms. Apache NetBeans is commonly compared to other free and open-source IDEs like Eclipse and VS Code, and to JetBrains' commercial IntelliJ IDEA, competing primarily on being a lightweight, fully free, and long-established option for Java development with strong out-of-the-box support for standard Java application types including Java SE, Java EE, and JavaFX.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '66ba6370-3244-451b-a008-2d5c51c1fb8e';

